  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"southwest-hallasan-osulloc-aewol","locale":"zh","product_id":"southwest-hallasan-osulloc-aewol","seo":{"pageTitle":"济州西南小团一日游：汉拿山、柱状节理带、雪绿茶博物馆与涯月 | AtoC Korea","metaDescription":"一条节奏均衡的济州西南小团路线，串联汉拿山轻徒步、大浦柱状节理带、天帝渊瀑布、雪绿茶博物馆与涯月咖啡街。"},"catalog_card":{"slug":"southwest-hallasan-osulloc-aewol","title":"济州西南小团一日游：汉拿山、雪绿茶博物馆与涯月","subtitle":"从汉拿山轻徒步出发，串联火山海岸、瀑布步道、茶园风景与轻松的涯月收尾。","region":"济州西南","duration":"8小时","stopsCount":6,"rating":4.8,"reviewCount":127,"badges":["适合第一次来济州的游客","济州西南"],"heroImage":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","thumbnail":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=600&q=80","priceLabel":"US$58起/人","shortCardDescription":"一条节奏均衡的济州西南路线，串联汉拿山轻徒步、火山海岸、天帝渊瀑布、雪绿茶博物馆与涯月咖啡街。"},"headlineLine1":"济州西南：汉拿山、茶园与涯月","headlineLine2":"小团一日游","price":{"amountLabel":"58","currency":"USD","per":"人"},"hero":{"imageUrl":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","imagePosition":"center 35%","tagline":"从汉拿山轻徒步出发，串联火山海岸、瀑布步道、茶园风景与轻松的涯月收尾。","pills":["适合第一次来济州的游客","济州西南"],"meta":{"duration":"8小时","region":"济州西南","stops":"6个景点","rating":4.8,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"概览"},{"id":"itinerary","label":"行程"},{"id":"details","label":"详情"},{"id":"faq","label":"常见问题"},{"id":"reviews","label":"评价"}],"glanceItems":[{"icon":"camera","label":"拍照友好度","value":"高"},{"icon":"mountain","label":"景观密度","value":"高"},{"icon":"footprints","label":"步行强度","value":"中等"},{"icon":"cloud-rain","label":"雨天适应度","value":"中等"},{"icon":"users","label":"家庭友好度","value":"良好"},{"icon":"scale","label":"节奏","value":"均衡"}],"galleryItems":[{"id":1,"type":"video","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","location":"整条路线","atmosphere":"一眼看懂这条一日游的整体节奏","alt":"济州西南路线的整体氛围"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","location":"汉拿山起始站","atmosphere":"清爽的山间空气","alt":"汉拿山御乘生岳步道"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","location":"火山海岸线","atmosphere":"极具力量感的玄武岩海岸","alt":"大浦柱状节理带的玄武岩海蚀崖"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","location":"森林步道与瀑布","atmosphere":"更清凉、更沉静的中段氛围","alt":"天帝渊瀑布森林步道"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=800&q=80","location":"茶园休憩站","atmosphere":"开阔的绿色风景与更柔和的节奏","alt":"雪绿茶博物馆与茶园一带的氛围"},{"id":6,"type":"video","src":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","location":"涯月海岸收尾","atmosphere":"轻松悠闲地结束这一天","alt":"海边的涯月咖啡街"}],"itineraryStops":[{"number":1,"time":"09:00","duration":"70分钟","name":"汉拿山御乘生岳（Eoseungsaengak）","category":"汉拿山轻徒步","description":"这一天从汉拿山开始，此时空气最清新，团队体力也最充足。御乘生岳是汉拿山较容易接近的步道之一，既能让你真正感受到从济州山地开启一天的氛围，又不会把行程变成高强度登山。","image":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","highlights":["一段虽短却很有成就感的汉拿山步行体验","可远望济州市、火山丘陵（Oreum）与汉拿山上部山势","比单纯的路边观景点更有沉浸感","在活动量与可达性之间取得了不错平衡，适合不同年龄层同行"],"timeUsed":["抵达后进行简短步道说明与节奏确认","主要上坡路段前往观景点","在较高观景区稍作停留、拍照后下行"],"whyOnRoute":"把团队在上午最充沛的体力用在最值得的地方，也让整天形成从山到海的清晰叙事线。","visitBasics":{"hours":"05:00起开放，可能因季节有所调整","closed":"部分天气条件下可能受限","admission":"免费","walking":"路线不长，但台阶较多，整体体感为中等"},"convenience":{"restroom":"御里牧（Eorimok）入口一带","parking":"可停车"},"smartNotes":{"photo":"到达较高观景位置后，广角风景照通常比近景人像更出片。","facilities":"入口区域的配套明显比步道中途更完善。","tip":"这一站更适合当作有重点的景观步行，不适合拖得太慢。"}},{"number":2,"time":"10:50","duration":"40分钟","name":"大浦柱状节理带","category":"玄武岩海岸","description":"从汉拿山下来后，视野会突然向大海打开。大浦柱状节理带是火山岩与海浪正面相遇的震撼海岸地形，也是当天第一个强烈的海岸亮点。","image":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","highlights":["济州代表性的六角玄武岩柱景观","紧接山地段之后，海岸反差更强烈","停留时间不长，但风景回报很高","延续了从汉拿山开始的济州火山地质故事线"],"timeUsed":["入口处简短讲解","沿主步道前往海岸观景区","拍照后集合"],"whyOnRoute":"让济州从山到海的火山地貌叙事自然不断线。","visitBasics":{"hours":"09:00–18:00（最晚入场 17:40）","closed":"全年开放","admission":"成人 2,000 韩元 / 儿童及青少年 1,000 韩元","walking":"轻松"},"convenience":{"restroom":"入口区域","parking":"收费停车场"},"smartNotes":{"photo":"稍带侧角度拍摄，通常比正面更能表现玄武岩纹理与海浪张力。","facilities":"设施不算多，但入口区域实用且足够。","tip":"这里的风和海雾变化很快，保持稳定节奏会更舒服。"}},{"number":3,"time":"11:50","duration":"60分钟","name":"午餐","category":"中段休整","description":"午餐是上午南海岸强景观段与下午更柔和的茶园、咖啡街段之间的节奏重置点。经过前半天的步行后，这一段能让后半程明显更舒适。","image":"https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80","highlights":["在汉拿山与柱状节理带之后自然重置节奏","对年龄层较广的团队来说更利于控节奏","让后续的瀑布与茶园段衔接更顺","也让最后的涯月收尾不会显得赶"],"timeUsed":["抵达并入座","用餐与短暂休息","准备前往下一站"],"whyOnRoute":"把午餐放在这里，能让整天节奏更均衡，不会出现前重后轻失衡。","visitBasics":{"hours":"视餐厅而定","closed":"因店铺而异","admission":"是否包含以具体产品条件为准，也可能现场自理","walking":"极少"},"convenience":{"restroom":"餐厅内","parking":"可停车"},"smartNotes":{"photo":"如果想补一些生活方式感的图库照片，这里特别适合拍餐食。","facilities":"餐饮配套通常完全够用。","tip":"午餐节奏稍微从容一点，通常比省下几分钟更能提升后半天体验。"}},{"number":4,"time":"13:00","duration":"50分钟","name":"天帝渊瀑布","category":"瀑布与森林步道","description":"经过开阔海岸后，天帝渊为路线加入更清凉、更葱郁的一层气质。桥梁、林间步道与瀑布观景点，让整体氛围在前往茶园与涯月前自然转柔。","image":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","highlights":["带阴凉感、节奏更平缓的瀑布站点","桥梁与林间步道带来明显的节奏变化","在开阔海岸段之后会显得格外清爽","也是茶园与咖啡街段之前很好的反差点"],"timeUsed":["入口处说明步行路线","穿行瀑布区的主要步行段","在观景点停留、拍照后返回"],"whyOnRoute":"它能在柱状节理带之后柔化整体氛围，也为更安静的后半天做铺垫。","visitBasics":{"hours":"09:00–17:50（最晚入场 17:10）","closed":"全年开放","admission":"成人 2,500 韩元 / 青少年及儿童 1,350 韩元","walking":"中等，含台阶，部分路段偶有湿滑"},"convenience":{"restroom":"入口区域","parking":"可停车"},"smartNotes":{"photo":"与其把所有元素硬塞进同一画面，不如用桥与瀑布做层次构图，效果通常更好。","facilities":"基础设施主要集中在入口附近。","tip":"这里有台阶，部分地面也可能湿滑，保持稳定节奏会更舒服。"}},{"number":5,"time":"14:20","duration":"60分钟","name":"O’Sulloc 雪绿茶博物馆","category":"茶园与文化站点","description":"在瀑布步道之后，O’Sulloc 会让整条路线的情绪明显重置。茶博物馆、商店与大片绿色茶园，让下午的气氛再次打开，然后再沿海前往涯月收尾。","image":"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=800&q=80","highlights":["开阔舒展的济州茶园景观","在森林段之后，茶文化站点会显得尤其轻松","绿色茶垄、现代建筑与甜品都很适合拍照","在前往涯月前，情绪会自然过渡得更柔和"],"timeUsed":["先简短说明博物馆区域布局","欣赏茶园、逛博物馆或商店，并安排咖啡时间","集合后前往涯月"],"whyOnRoute":"它能在上午较活跃的段落后降低体力强度，并把最后一段自然交给更柔和的海岸节奏。","visitBasics":{"hours":"通常为 09:00–18:00，可能随季节调整","closed":"全年开放","admission":"免费","walking":"轻松"},"convenience":{"restroom":"博物馆与咖啡区","parking":"可停车"},"smartNotes":{"photo":"茶园的大场景与咖啡区侧角度，通常比只拍产品特写更好看。","facilities":"有洗手间、饮品和座位，是后半天最舒适的站点之一。","tip":"与其只匆匆看博物馆，不如把风景和咖啡氛围一起体验，会更有满足感。"}},{"number":6,"time":"15:50","duration":"60分钟","name":"涯月咖啡街","category":"海边咖啡收尾","description":"涯月为这一天画上更轻松、更舒展的句号。从山间空气、玄武岩海岸、瀑布步道到茶园风景之后，以海景、咖啡露台与轻快的海岸节奏收尾，非常合适。","image":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","highlights":["非常适合作为一天结束的海边咖啡氛围","以涯月汉潭海岸一带为核心，更偏生活方式感的柔和收尾","可自由安排咖啡、拍照与简短海边散步","与上午偏活跃的节奏形成舒服对比"],"timeUsed":["抵达后简短说明区域动线","自由享用咖啡或进行短距离海边散步","集合返程"],"whyOnRoute":"涯月是很适合做情绪收尾的地方，能把节奏自然拉开，让整条路线在结束时更轻盈而不是更沉重。","visitBasics":{"hours":"区域全天开放，各咖啡馆营业时间不同","closed":"区域本身无统一休息日","admission":"免费","walking":"轻松"},"convenience":{"restroom":"视所使用咖啡馆而定","parking":"区域内可停车"},"smartNotes":{"photo":"下午稍晚时的逆光与面海露台，通常最容易拍出好看的画面。","facilities":"舒适度取决于选择哪一家咖啡馆，因此灵活安排通常比固定死一家更好。","tip":"这一站让客人拥有更自由的节奏，通常会比全程被紧紧带着走更受欢迎。"}}],"routeFlowStops":[{"id":"01","name":"御乘生岳","theme":"汉拿山"},{"id":"02","name":"柱状节理带","theme":"海岸"},{"id":"03","name":"午餐","theme":"休整"},{"id":"04","name":"天帝渊","theme":"瀑布"},{"id":"05","name":"雪绿茶博物馆","theme":"茶园"},{"id":"06","name":"涯月","theme":"海岸"}],"routePhases":[{"label":"上午","range":"1-2","theme":"从汉拿山到海岸","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"中午至下午前段","range":"3-4","theme":"午餐与瀑布","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"收尾","range":"5-6","theme":"茶园与涯月","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"这条路线如何展开","subtitle":"从汉拿山与火山海岸开始，穿过午餐与瀑布段，再到茶园与涯月海岸收尾。整体时间大约为 09:00–17:30。"},"whyTourWorks":{"bestFor":["第一次来济州的游客与情侣","成人家庭出游","想同时看自然风景、茶园，并希望以更柔和节奏收尾的旅客","体力不错的中年及年长旅客"],"lessIdealFor":["想完全避开短台阶或上坡步行的旅客","高度依赖婴儿车的团队","以很小的小朋友为核心设计的行程"],"routeLogicSections":[{"title":"节奏与结构","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"把汉拿山放在体力最好的时段","detail":"先走御乘生岳，短上坡会显得更轻松，也能让后续自然衔接到海岸段。"},{"label":"午餐安排在恰到好处的位置","detail":"午餐把前半天更开阔、更有冲击力的景观段，与后面更平缓的瀑布和茶园段自然分开。"},{"label":"在 O’Sulloc 之后以更轻松的方式收尾","detail":"茶园先把情绪柔化下来，再由涯月用咖啡、海景和更轻快的节奏自然结束这一天。"}]},{"title":"路线设计逻辑","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"先山后海","detail":"路线先用汉拿山建立高度感与层次感，再在柱状节理带把视野强烈地打开到海岸。"},{"label":"先瀑布，再进入茶园段","detail":"天帝渊先让整体节奏沉下来，然后由 O’Sulloc 用更轻、更柔和的方式打开后半天。"},{"label":"以咖啡海岸作收尾","detail":"涯月不是又一个高强度打卡点，而是偏生活方式感的海岸收尾，让一天结束得更柔和。"}]},{"title":"遇到天气变化时","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"汉拿山段受天气影响较明显","detail":"御乘生岳可能因天气突然变化或步道管制而需要调整。"},{"label":"海岸段风感更直接","detail":"柱状节理带与涯月比内陆站点更容易受到风势影响。"},{"label":"整体步行量虽均衡，但仍需留意台阶","detail":"整条路线整体可控，但御乘生岳与天帝渊依然需要注意台阶与短上坡。"}]}]},"practicalAccordionItems":[{"id":"pickup","title":"接送与返回","preview":"济州市区酒店大堂接送","content":["08:20–08:50 在酒店大堂接您","预计返回时间约为 17:50–18:20","可按需求协商机场接送","最终接车时间将在前一晚确认"]},{"id":"walking","title":"步行与路况","preview":"整体强度中等，大多数客人都能轻松跟上","content":["全天总步行距离通常约为 4.5–5.5 公里。","御乘生岳：短距离上坡，但台阶较多。","柱状节理带：较轻松的海岸步道。","天帝渊：森林步道、台阶较多，部分路段可能潮湿。","O’Sulloc 和涯月：相对轻松，更容易掌握节奏。","建议穿抓地力较好的步行鞋。"]},{"id":"weather","title":"天气与临时调整","preview":"通常照常出发，如有需要会灵活调整","content":["小雨：通常按原计划进行。","大雨或步道受限：御乘生岳段可能缩短或调整。","强风：柱状节理带或涯月的停留时间可能缩短。","若后半天天气变差：下午的重点可能会更偏向 O’Sulloc。","若景点临时关闭：会改用替代站点。"]},{"id":"wear","title":"穿着与携带建议","preview":"建议准备好走的鞋、分层穿搭与轻便外套","content":["抓地力好的鞋子","适合山地与海岸温差的分层穿搭","轻便防风外套","帽子与防晒用品","饮用水"]},{"id":"included","title":"费用包含 / 不含","preview":"导游、车辆、接送与门票已含","variant":"included","content":["英文导游","小团车辆","济州市区酒店接送","全部景点门票","瓶装水","午餐（现场自理）","个人购物支出","导游小费"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"实时天气接入"},"tomorrow":{"temp":"—","label":"每日更新"}},"seasonalVariations":[{"name":"春季","icon":"flower","description":"油菜花季时，沿海部分路段会多一层明亮的黄色。","tag":"花季限定","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"夏季","icon":"sun","description":"白天更长，整条路线的绿色层次也会显得格外浓郁鲜明。","tag":"日照时间最长","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"秋季","icon":"leaf","description":"天气清朗时，山、海与茶园的层次会显得尤其利落分明。","tag":"视野最佳","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"冬季","icon":"snow","description":"整体氛围通常更安静，白天更短，节奏也更沉静。","tag":"更安静的季节感","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"check-circle","title":"持牌本地正规运营","description":"在济州合法合规开展带团服务","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"围绕西南经典线路设计","description":"整条路线专为济州西南动线打造","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"小团出行体验","description":"最多 8 位客人","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"预订后立即","title":"即时确认","detail":"您会收到包含当天路线摘要的预订确认信息。"},{"timing":"出发前 12 小时","title":"12 小时提醒","detail":"会提前发送天气说明与可能的路线调整信息。"},{"timing":"出发前一晚","title":"最终接车通知","detail":"会告知您的准确接车时间与司机联系方式。"},{"timing":"出发当天早晨","title":"当天路线提示","detail":"根据现场实时情况，提供简短的早间说明。"},{"timing":"行程进行中","title":"沿途实时讲解","detail":"在每一站为您提供恰到好处的信息与提示。"},{"timing":"行程结束后","title":"后续支持","detail":"如有需要，结束后仍可继续提供建议与补充说明。"}],"staticQuestions":[{"id":"first-time","question":"第一次来济州，适合参加这条路线吗？","answer":"适合。这条线路能在一天内均衡体验汉拿山风景、火山海岸、瀑布步道、茶园氛围与轻松的涯月收尾。"},{"id":"walking","question":"步行难度高吗？","answer":"整体不算高。御乘生岳是活动量最大的部分，台阶较多，但一天中其余站点整体都比较好走。"},{"id":"rain","question":"下雨天还能正常出发吗？","answer":"可以。雨天通常仍可成行，但御乘生岳或较暴露的海岸段，可能会根据实际情况缩短停留时间。"},{"id":"parents","question":"适合和父母或年长家人一起参加吗？","answer":"多数情况下适合。尤其适合成人家庭出游，但前提是同行者能接受台阶与短距离上坡。"},{"id":"children","question":"可以带孩子参加吗？","answer":"可以。特别适合大约 8 岁以上、能够跟上短距离步行与一日游节奏的孩子。"},{"id":"order","question":"景点顺序会因现场情况调整吗？","answer":"会。山上天气、海边风势、交通和现场客流，都可能让顺序出现小幅调整，尤其是御乘生岳与海岸段。"},{"id":"lunch","question":"午餐包含在费用内吗？","answer":"这取决于具体产品条件。路线中预留了午餐时间，但餐费是否包含，以您实际预订的方案为准。"},{"id":"why-eoseungsaengak","question":"为什么从御乘生岳开始？","answer":"因为它能在团队体力最好的时段，先把汉拿山的真实氛围带出来，同时又不会让整条路线变成高强度登山行程。"},{"id":"why-jusangjeolli","question":"为什么汉拿山之后要去柱状节理带？","answer":"因为这样能让济州的火山故事从山地地形自然过渡到更具冲击力的玄武岩海岸。"},{"id":"why-osulloc","question":"为什么 O’Sulloc 安排在涯月之前？","answer":"因为 O’Sulloc 会先把瀑布段之后的情绪柔化下来，这样最后到涯月时，会显得更轻松、更舒服。"},{"id":"later-structure","question":"为什么后半天是这样安排的？","answer":"午餐和天帝渊会先把上午偏开阔的节奏稳下来，随后由 O’Sulloc 以更轻松的茶园氛围过渡，再用涯月结束一天，不会让收尾显得沉重。"}],"guestReviews":[{"id":1,"author":"Sarah M.","avatar":"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100&q=80","location":"新加坡","date":"2024年3月","rating":5,"title":"用一天看懂济州西南，节奏真的很舒服","text":"整条路线的节奏非常好。从汉拿山开始，让这一天一上来就很有状态，也让后面的柱状节理带显得更震撼。我尤其喜欢从 O’Sulloc 过渡到涯月的方式，下午的氛围自然慢下来，让整天都显得很顺。","helpful":24,"verified":true,"tripType":"情侣","photos":["https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=400&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400&q=80"]},{"id":2,"author":"James K.","avatar":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&q=80","location":"香港","date":"2024年3月","rating":5,"title":"一条完成度很高的西南路线，收尾尤其舒服","text":"我在韩国参加过几次一日游，这条路线会让人印象特别深，就是因为顺序设计得很好。导游把汉拿山、海崖和天帝渊之间的节奏处理得很顺，而 O’Sulloc 到涯月的收尾，也让整天显得均衡而不累。","helpful":18,"verified":true,"tripType":"家庭","photos":[]},{"id":3,"author":"Yuki T.","avatar":"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&q=80","location":"东京","date":"2024年2月","rating":4,"title":"我尤其喜欢在涯月结束这一天","text":"整体体验很好。御乘生岳比我预想中更适合作为开场，O’Sulloc 也正好是去涯月前最舒服的一站。我给四星只是因为我个人还想在涯月多待一会儿，不过我也理解行程时间有限。","helpful":12,"verified":true,"tripType":"独自旅行","photos":["https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=400&q=80"]},{"id":4,"author":"Michael R.","avatar":"https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100&q=80","location":"悉尼","date":"2024年2月","rating":5,"title":"路线内容比我想象中更丰富","text":"我原本主要是冲着风景来参加的，但最后最让我记住的，是整天的衔接真的很好。汉拿山、玄武岩海岸、瀑布、茶园和涯月海边，都像是在讲同一个完整的故事，而小团形式也让每一次转换都很顺畅。","helpful":31,"verified":true,"tripType":"朋友同行","photos":[]}],"reviewsSummary":{"averageRating":4.8,"totalReviews":127,"ratingDistribution":[{"stars":5,"count":98,"percentage":77},{"stars":4,"count":21,"percentage":17},{"stars":3,"count":6,"percentage":5},{"stars":2,"count":1,"percentage":1},{"stars":1,"count":1,"percentage":1}],"highlights":[{"label":"景色","count":89},{"label":"导游","count":76},{"label":"节奏","count":54},{"label":"涯月收尾","count":41}]},"sticky_booking_bar":{"note":"checkout_tour_id 在运行时从 Supabase / env 解析；不属于静态 JSONB 内容。","price":{"amountLabel":"58","currency":"USD","per":"人"}},"matching_profile":{"product_type":"small_group","route_type":"fixed_route","region_type":"southwest","region_tags":["jeju_southwest","hallasan_to_aewol"],"theme_tags":["hallasan","basalt","waterfall","tea","cafe","balanced_pace","one_day"],"poi_tags":["eoseungsaengak","jusangjeolli","cheonjeyeon","osulloc","aewol"],"pace_level":3,"walking_level":3,"scenic_level":5,"photo_level":5,"culture_level":3,"relax_level":4,"first_time_fit":5,"family_fit":4,"senior_fit":3,"couple_fit":5,"active_traveler_fit":3,"one_day_fit":4,"same_day_flight_fit":2,"rain_fit":3,"value_for_money_fit":5,"iconic_landmark_fit":4,"cafe_fit":5,"adult_family_fit":4,"young_kids_fit":3,"senior_active_fit":4,"senior_general_fit":3,"mobility_friendly_fit":2,"stroller_fit":1,"indoor_ratio":38,"weather_sensitivity":3,"local_culture_fit":3,"shopping_fit":2,"storytelling_fit":4,"comfort_level":4,"budget_fit":5,"premium_fit":3,"small_group_fit":5,"private_fit":1,"bus_fit":1,"price_band":"mid","pickup_base":"jeju_city","return_time_band":"17:50-18:20","duration_band":"8h","min_recommended_age":8,"hard_constraints":{"avoidIf":["tight_same_day_departure","strict_same_day_flight_schedule","strict_no_stairs_request"],"notIdealFor":["toddlers","stroller_heavy","very_low_mobility"]},"walking_notes":["Overall walking is moderate for a full-day route.","Eoseungsaengak is short, but it includes many stairs.","Cheonjeyeon includes stairs and can have wet or slippery sections.","Jusangjeolli, O’Sulloc, and Aewol are easier segments where the pace is easier to manage.","Walking shoes with good grip are recommended."],"keywords":["jeju southwest day tour","hallasan osulloc aewol","jeju tea fields and coast","eoseungsaengak","jusangjeolli","cheonjeyeon waterfall","o''sulloc tea museum","aewol cafe street","balanced jeju day tour","jeju first trip southwest","제주 서남부 투어","오설록 애월 한라산","濟州西南一日遊","漢拏山 OSULLOC 애월"],"synonym_hints":["jeju southwest highlights","hallasan tea fields aewol day tour","balanced jeju small group","nature tea and cafe coast","softer afternoon finish","relaxed southwest jeju route","mountain to coast to tea fields"],"profile_version":3,"is_active":true},"matching_metadata":{"schema_version":"tour_matching_profile.v1","last_reviewed_at":"2026-04-22","score_rationale":{"pace_level":"An 8-hour route with six stops and a deliberately softer second half, so it is balanced rather than rushed.","walking_level":"Moderate overall. The main effort comes from the Eoseungsaengak stairs and the Cheonjeyeon walking path.","scenic_level":"Strong visual layering across Hallasan, basalt coastline, waterfall forest, tea fields, and the Aewol coast.","photo_level":"Very strong for variety. The route mixes mountain views, volcanic cliffs, tea-field scenery, and cafe-coast atmosphere.","culture_level":"Nature leads the day, but O’Sulloc adds tea-culture context and the route supports stronger narrative storytelling than a simple scenic loop.","relax_level":"The afternoon becomes noticeably softer after lunch, especially through O’Sulloc and Aewol.","first_time_fit":"A very strong choice for first-time Jeju visitors who want balance rather than a full-island sprint.","family_fit/young_kids_fit/stroller_fit":"Works well for adult families and school-age children, but stairs and short uphill sections make it weak for stroller-heavy groups.","senior_fit/senior_general_fit/mobility_friendly_fit":"Reasonable for active seniors, but not a true low-mobility route because of stairs at Eoseungsaengak and Cheonjeyeon.","same_day_flight_fit":"Possible only with a generous evening buffer because return is still late afternoon to early evening.","rain_fit/indoor_ratio/weather_sensitivity":"Partly protected by lunch, O’Sulloc, and optional cafe time, but the mountain and coastal sections still react clearly to weather.","local_culture_fit/shopping_fit":"Tea-culture context is present through O’Sulloc, but this is not a shopping-led or village-culture-led route.","small_group_fit/private_fit/bus_fit":"Best operated as a small-group van route. The current structure is not designed as a private-only or large-bus product.","price_band/budget_fit/premium_fit":"At US$58, it is strong on value for money, positioned in the mid-price band rather than true premium.","hard_constraints":"Keep it conservative for very low mobility, stroller-heavy groups, and guests with tight same-day departure schedules."}}}'::jsonb
)
